SELECT COUNT(*)
FROM datasets
INNER JOIN users ON datasets.curator_id = users.user_id;

SELECT dataset_id, title
FROM datasets
WHERE gse = 'GSE420' OR gse = 'GSE421';

SELECT d.organism_ch1, p.platform_name, d.experimental_conditions, d.data_quality_score, p.description
FROM datasets d
INNER JOIN platforms p ON d.gpl = p.platform_id;

SELECT DISTINCT organism_ch1 
FROM datasets 
WHERE version_controlled = 1 AND accessibility = 'public';

SELECT title
FROM datasets
WHERE source_name_ch1 = 'United States';

SELECT organism_ch1, experimental_conditions, data_type, pubmed_id
FROM datasets
WHERE organism_ch1 IN ('Homo sapiens', 'Mus musculus');

SELECT COUNT(*)
FROM datafiles
WHERE file_size > 1;

SELECT d.title, d.organism_ch1
FROM datasets d
WHERE d.gpl = 'GPL12345' AND d.accessibility = 'public';

SELECT o.organism_name, u.user_name
FROM (SELECT organism_name FROM organisms WHERE organism_id < 10050) o
CROSS JOIN (SELECT user_name FROM users WHERE user_id < 5) u;

SELECT *
FROM datasets
WHERE data_quality_score < (SELECT AVG(data_quality_score) FROM datasets);

SELECT title
FROM publications
WHERE pubmed_id NOT IN (
    SELECT pubmed_id
    FROM datasets
);

SELECT DISTINCT u.user_name
FROM users u
JOIN access_logs al ON u.user_id = al.user_id;
